"use client";

import { useSyncedState } from "rwsdk/use-synced-state/client";

export const Counter = ({ runId }: { runId: string }) => {
  const [count, setCount] = useSyncedState<number>(0, "counter", runId);

  return (
    <div>
      <p>
        Count: <span id="count-value">{count}</span>
      </p>
      <button onClick={() => setCount((c) => c + 1)}>Increment</button>
      <button onClick={() => setCount((c) => c - 1)}>Decrement</button>
    </div>
  );
};

import { Counter } from "./counter.js";

export const Home = ({ env }: { env: Cloudflare.Env }) => {
  const runId = env.ZEALT_RUN_ID || "default-run";

  return (
    <div>
      <h1>Collaborative Counter</h1>
      <Counter runId={runId} />
    </div>
  );
};

import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";
import {
  syncedStateRoutes,
  SyncedStateServer,
} from "rwsdk/use-synced-state/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";

export { SyncedStateServer };

export type AppContext = {};

const syncedState = syncedStateRoutes(
  (env) => env.SYNCED_STATE as DurableObjectNamespace<SyncedStateServer>,
);

export default defineApp([
  setCommonHeaders(),
  ({ ctx }) => {
    // setup ctx here
    ctx;
  },
  ...syncedState,
  route("/api/count", async ({ env }) => {
    const namespace = env.SYNCED_STATE as DurableObjectNamespace<SyncedStateServer>;
    const runId = env.ZEALT_RUN_ID || "default-run";
    const id = namespace.idFromName(runId);
    const stub = namespace.get(id);
    const count = (await stub.getState("counter")) ?? 0;
    return Response.json({ count });
  }),
  render(Document, [route("/", Home)]),
]);

import { defineConfig } from "vite";
import { redwood } from "rwsdk/vite";
import { cloudflare } from "@cloudflare/vite-plugin";

export default defineConfig({
  plugins: [
    cloudflare({
      viteEnvironment: { name: "worker" },
    }),
    redwood(),
  ],
  server: {
    host: "0.0.0.0",
    port: 5173,
  },
});
